void jiami(char *str) {
	int len = strlen(str);
	for(int i=0; i<len; i++) {
		if(str[i]>='a'&&str[i]<='z') {
			str[i] = str[i] + 4;
			if(str[i]>'z') {
				str[i] = str[i] - 26;
			}
		} else if(str[i]>='A'&&str[i]<='Z') {
			str[i] = str[i] + 4;
			if(str[i]>'Z') {
				str[i] = str[i] - 26;
			}
		}
	}
}

