#include <iostream>
#include <iomanip> // Required for std::fixed and std::setprecision

int main() {
    double fahrenheit;

    // Read the Fahrenheit temperature from the user
    std::cin >> fahrenheit;

    // Convert Fahrenheit to Celsius using the formula: C = 5/9 * (F - 32)
    double celsius = 5.0 / 9.0 * (fahrenheit - 32);

    // Output the Celsius temperature, formatted to two decimal places
    // std::fixed ensures that the decimal point is always shown, and std::setprecision(2)
    // sets the number of digits after the decimal point to 2.
    std::cout << "c=" << std::fixed << std::setprecision(2) << celsius << std::endl;

    return 0;
}

