#include <stdio.h>
#include <math.h> // for pow (optional, can use loops for powers of 10)

int main() {
    int n;
    scanf("%d", &n);

    // --- 1. 求位数 ---
    int temp = n;
    int digits = 0;
    if (temp == 0) { // 特殊处理0
        digits = 1;
    } else {
        while (temp > 0) {
            temp /= 10;
            digits++;
        }
    }
    printf("%d\n", digits);

    // --- 2. 顺序输出每一位数字 (从高位到低位) ---
    // 重新初始化temp为n
    temp = n;
    int divisor = 1;
    // 计算出最大的10的幂次，用于取最高位
    for (int i = 1; i < digits; i++) {
        divisor *= 10;
    }

    if (n == 0) { // 如果输入是0
        printf("0\n");
    } else {
        while (divisor > 0) {
            printf("%d", temp / divisor); // 输出当前位的数字
            temp %= divisor;             // 去掉已经输出的位
            divisor /= 10;               // 降低除数，准备取下一位
            if (divisor > 0) {           // 如果不是最后一个数字，就输出空格
                printf(" ");
            }
        }
        printf("\n");
    }


    // --- 3. 逆序输出各位数字 (从低位到高位) ---
    temp = n; // 重新初始化temp为n
    if (n == 0) { // 如果输入是0
        printf("0\n");
    } else {
        while (temp > 0) {
            printf("%d", temp % 10); // 输出个位
            temp /= 10;              // 去掉个位
        }
        printf("\n");
    }


    return 0;
}

