using namespace std;
int main(){
    int code;
    int profit;
    cin>>profit;
    if(profit<=100000) code=1;
    else if(profit<=200000) code=2;
    else if(profit<=400000) code=3;
    else if(profit<=600000) code=4;
    else if(profit<=1000000) code=5;
    else code=6;;
    double bonus=0;
    switch(code){
        case 1:bonus=profit*0.1;break;
        case 2:bonus=100000*0.1+(profit-100000)*0.075;break;
        case 3:bonus=100000*0.1+100000*0.075+(profit-200000)*0.05;break;
        case 4:bonus=100000*0.1+100000*0.075+200000*0.050+(profit-400000)*0.03;break;
        case 5:bonus=100000*0.1+100000*0.075+200000*0.050+200000*0.03+(profit-600000)*0.015;break;
        case 6:bonus=100000*0.1+100000*0.075+200000*0.050+200000*0.03+400000*0.015+(profit-1000000)*0.01;break;
        default:
        cout<<"输入错误"<<endl;
        return 1;
    }
    cout<<(int)bonus<<endl;
    return 0;
}

