#include <iostream>

int main() {
    // Iterate through all three-digit numbers
    for (int num = 100; num <= 999; ++num) {
        int original_num = num; // Store the original number for comparison
        int hundreds = original_num / 100; // Get the hundreds digit
        int tens = (original_num / 10) % 10; // Get the tens digit
        int units = original_num % 10; // Get the units digit

        // Calculate the sum of the cubes of its digits
        int sum_of_cubes = hundreds * hundreds * hundreds +
                           tens * tens * tens +
                           units * units * units;

