#include <iostream>

int main() {
    int N;
    std::cin >> N; // Read the number of days N

    // On the N-th day morning, 1 peach is left. This is P_N in our formula.
    long long peaches_on_current_day = 1; 

    // Work backwards from day N to day 2 to find peaches on day 1
    // We need to loop N-1 times to go from day N to day 1.
    // For N=1, the loop won't run, and it correctly outputs 1.
    for (int i = N; i > 1; --i) {
        // Apply the reverse formula: P_k = 2 * (P_{k+1} + 1)
        // In our loop, peaches_on_current_day is P_{k+1}
        // And we calculate P_k, which becomes the new peaches_on_current_day for the next iteration.
        peaches_on_current_day = 2 * (peaches_on_current_day + 1);
    }

    // After the loop, peaches_on_current_day holds the number of peaches on Day 1.
    std::cout << peaches_on_current_day << std::endl;

    return 0; // Indicate successful program execution
}

