void nixu(char *str){
	if(str == NULL) return;
	int len = strlen(str);
	char* arr = (char*)malloc((len+1)*sizeof(char));
	for(int i = 0;i<len;i++){
		arr[i] = str[i];
		if(i==len-1) arr[len] = '\0';
	}
	for(int i = 0;i<len;i++){
		str[i] = arr[len-i-1];
	}
	free(arr);
}

