using namespace std;

// 递归构造FBI树并输出后序遍历
void buildFBI(const string& s) {
    int len = s.size();
    // 1. 判断当前串的类型
    bool all0 = true, all1 = true;
    for (char c : s) {
        if (c == '1') all0 = false;
        if (c == '0') all1 = false;
    }
    char type;
    if (all0) type = 'B';
    else if (all1) type = 'I';
    else type = 'F';

    // 2. 若长度>1，递归处理左右子串
    if (len > 1) {
        string left = s.substr(0, len/2);
        string right = s.substr(len/2);
        buildFBI(left);   // 后序：先左
        buildFBI(right);  // 后序：再右
    }

    // 3. 后序：最后输出当前节点类型
    cout << type;
}

int main() {
    int N;
    string s;
    cin >> N >> s;
    buildFBI(s);
    cout << endl;
    return 0;
}

#include <iostream>
#include <string>
using namespace std;

// 后序遍历构建
string build(string s) {
    char root;
    // 判断根节点类型
    if (s.find('0') == string::npos) {
        root = 'I'; // 全是1
    } else if (s.find('1') == string::npos) {
        root = 'B'; // 全是0
    } else {
        root = 'F'; // 混合
    }

    if (s.size() == 1) {
        return string(1, root); // 单个字符就是叶子节点
    }

    int mid = s.size() / 2;
    string left = build(s.substr(0, mid));
    string right = build(s.substr(mid));
    return left + right + root; // 后序：左 + 右 + 根
}

int main() {
    int N;
    string s;
    cin >> N >> s;
    cout << build(s) << endl;
    return 0;
}

