int maxSubSeqLenth(char *c, int len)
{
    for (int maxlen = len - 1; maxlen > 0; maxlen--)
    {
        int flag = 1;
        for (int j = 0; j < maxlen; j++)
        {
            if (c[j] != c[len - maxlen + j])
            {
                flag = 0;
                break;
            }
        }
        if (flag == 1)
            return maxlen;
    }
    return 0;
}

