using namespace std;

// 二叉树结点结构
struct TreeNode {
    char val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(char c) : val(c), left(nullptr), right(nullptr) {}
};

// 全局索引，用于递归构造二叉树
int idx = 0;

// 根据带虚结点的前序串构造二叉树
TreeNode* buildTree(const string& pre) {
    if (idx >= pre.size() || pre[idx] == '#') {
        idx++;
        return nullptr;
    }
    TreeNode* root = new TreeNode(pre[idx++]);
    root->left = buildTree(pre);
    root->right = buildTree(pre);
    return root;
}

// 中序遍历（不含虚结点）
void inOrder(TreeNode* root, string& res) {
    if (!root) return;
    inOrder(root->left, res);
    res += root->val;
    inOrder(root->right, res);
}

// 后序遍历（不含虚结点）
void postOrder(TreeNode* root, string& res) {
    if (!root) return;
    postOrder(root->left, res);
    postOrder(root->right, res);
    res += root->val;
}

// 层次遍历（不含虚结点）
void levelOrder(TreeNode* root, string& res) {
    if (!root) return;
    queue<TreeNode*> q;
    q.push(root);
    while (!q.empty()) {
        TreeNode* node = q.front();
        q.pop();
        res += node->val;
        if (node->left) q.push(node->left);
        if (node->right) q.push(node->right);
    }
}

// 释放二叉树内存（避免内存泄漏）
void deleteTree(TreeNode* root) {
    if (!root) return;
    deleteTree(root->left);
    deleteTree(root->right);
    delete root;
}

int main() {
    string pre;
    while (cin >> pre) {
        idx = 0; // 重置索引
        TreeNode* root = buildTree(pre);
        
        string in, post, level;
        inOrder(root, in);
        postOrder(root, post);
        levelOrder(root, level);
        
        cout << in << " " << post << " " << level << endl;
        
        deleteTree(root); // 释放内存
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// 二叉树结点结构
typedef struct Node {
    char data;
    struct Node* left;
    struct Node* right;
} Node;

// 创建新结点
Node* createNode(char data) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->data = data;
    node->left = NULL;
    node->right = NULL;
    return node;
}

// 根据前序遍历序列构建二叉树
Node* buildTree(const char* pre, int* index) {
    if (pre[*index] == '#') {
        (*index)++;
        return NULL;
    }
    Node* root = createNode(pre[*index]);
    (*index)++;
    root->left = buildTree(pre, index);
    root->right = buildTree(pre, index);
    return root;
}

// 中序遍历（不含虚结点）
void inOrder(Node* root, char* result, int* len) {
    if (root == NULL) return;
    inOrder(root->left, result, len);
    result[(*len)++] = root->data;
    inOrder(root->right, result, len);
}

// 后序遍历（不含虚结点）
void postOrder(Node* root, char* result, int* len) {
    if (root == NULL) return;
    postOrder(root->left, result, len);
    postOrder(root->right, result, len);
    result[(*len)++] = root->data;
}

// 层次遍历（不含虚结点）
void levelOrder(Node* root, char* result, int* len) {
    if (root == NULL) return;
    Node* queue[2000]; // 队列，存储结点指针
    int front = 0, rear = 0;
    queue[rear++] = root;
    while (front < rear) {
        Node* curr = queue[front++];
        result[(*len)++] = curr->data;
        if (curr->left != NULL) {
            queue[rear++] = curr->left;
        }
        if (curr->right != NULL) {
            queue[rear++] = curr->right;
        }
    }
}

// 释放二叉树内存
void freeTree(Node* root) {
    if (root == NULL) return;
    freeTree(root->left);
    freeTree(root->right);
    free(root);
}

int main() {
    char pre[2001];
    while (fgets(pre, sizeof(pre), stdin) != NULL) {
        // 去除输入中的换行符
        pre[strcspn(pre, "\n")] = '\0';
        int index = 0;
        Node* root = buildTree(pre, &index);
        
        // 计算中序遍历
        char in[2001] = "";
        int in_len = 0;
        inOrder(root, in, &in_len);
        
        // 计算后序遍历
        char post[2001] = "";
        int post_len = 0;
        postOrder(root, post, &post_len);
        
        // 计算层次遍历
        char level[2001] = "";
        int level_len = 0;
        levelOrder(root, level, &level_len);
        
        // 输出结果
        printf("%s %s %s\n", in, post, level);
        
        // 释放内存
        freeTree(root);
    }
    return 0;
}

