    if (a < b) {
        a = b;
    }
}

template<class T>
void chmin(T &a, T b) {
    if (a > b) {
        a = b;
    }
}

void solve(){
    int n;
    std::cin>>n;
    std::vector<PII> r(n);
    for(int i=0;i<n;i++) std::cin>>r[i][0]>>r[i][1];
    std::vector<int> tmp;
    tmp.push_back(0);
    for(auto p:r){
        tmp.push_back(p[0]);
        tmp.push_back(p[1]+p[0]);
    }
    std::sort(tmp.begin(),tmp.end());
    tmp.erase(std::unique(tmp.begin(),tmp.end()),tmp.end());
    auto get=[&](int u){
        return std::lower_bound(tmp.begin(),tmp.end(),u)-tmp.begin();
    };
    std::sort(r.begin(),r.end());
    int sz=tmp.size();
    std::vector<int> f[2];
    int now,last;
    now=0;
    last=1;
    for(int i=0;i<2;i++) f[i].assign(sz+1,-1);
    f[last][0]=0;
    for(auto p:r){
        int u=get(p[0]);
        int v=get(p[1]+p[0]);
        f[now]=f[last];
        for(int i=0;i<=u;i++) chmax(f[now][v],f[last][i]+1);
        std::swap(now,last);
        //for(int i=0;i<sz;i++) std::cerr<<f[last][i]<<" "<<tmp[i]<<"\n";
        //std::cerr<<"\n";
    }
    int ans=0;
    for(int i=0;i<=sz;i++) chmax(ans,f[last][i]);
    std::cout<<ans<<"\n";
}

