int main() {
    int N;
    cin >> N;
    
    if (N == 0) { // 边界处理：N=0时无牌，次数为0
        cout << 0 << endl;
        return 0;
    }
    
    int pos = 1; // 跟踪第1张牌的位置，初始在位置1
    int M = 0;   // 洗牌次数
    
    do {
        // 计算洗牌后的新位置
        if (pos <= N) {
            pos = 2 * pos;
        } else {
            pos = 2 * (pos - N) - 1;
        }
        M++; // 洗牌次数+1
    } while (pos != 1); // 直到位置回到1，停止循环
    
    cout << M << endl;
    return 0;
}

