    {
        if(s[i]=='+'||s[i]=='-'||s[i]=='\0')
        {
            if(k)
            {
                sum-=a;
            }
            else
            {
                sum+=a;
            }
            a=0;
            if(s[i]=='+')k=0;
            if(s[i]=='-')k=1;            
        }
        else
        {
             a*=10;
             a+=s[i]-'0';
        }
    }
    return sum;
}               
 
void back(int i,int n,char s[],int &answer)
{
    if(s[i-1]=='9')
    {
        s[i]='\0';
        int sum=calcu(s);
        if(sum==n)answer++;
    }
    else
    {
        if(s[i-1]=='+'||s[i-1]=='-')
        {
            s[i]=s[i-2]+1;
            back(i+1,n,s,answer);
        }
        else
        {
            s[i]=s[i-1]+1;
            back(i+1,n,s,answer);
            s[i]='+';
            back(i+1,n,s,answer);
            s[i]='-';
            back(i+1,n,s,answer);
        }
    }
}                
 
