            // 入栈直到当前需要的数
            while (current <= num) {
                stk.push(current);
                ops += 'P';
                current++;
            }

            // 如果栈顶元素等于当前需要的数，出栈
            if (!stk.empty() && stk.top() == num) {
                stk.pop();
                ops += 'Q';
            } else {
                // 无法得到该序列
                flag = false;
                break;
            }
        }

        if (flag) {
            cout << ops << endl;
        } else {
            // 输出到不能操作的位置的操作序列，然后输出 "error"
            int errorPos = ops.size();
            if (errorPos > 0) {
                cout << ops.substr(0, errorPos) << " error" << endl;
            } else {
                cout << "error" << endl;
            }
        }
    }

