int calculateQuicksum(const std::string &packet) {
    int sum = 0;
    for (size_t i = 0; i < packet.length(); ++i) {
        int value = (packet[i] == ' ') ? 0 : packet[i] - 'A' + 1;
        sum += (i + 1) * value;
    }
    return sum;
}
