using namespace std;
 
int factorial(int n) {
    int res = 1;
    for (int i = 2; i <= n; i++) {
        res *= i;
    }
    return res;
}
 
int permutationRank(vector<int>& nums) {
    int n = nums.size();
    vector<int> factorials(n);
    for (int i = 0; i < n; i++) {
        factorials[i] = factorial(i);
    }
    int rank = 0;
    for (int i = 0; i < n; i++) {
        int smaller = 0;
        for (int j = i + 1; j < n; j++) {
            if (nums[j] < nums[i]) {
                smaller++;
            }
        }
        rank += smaller * factorials[n - i - 1];
    }
    return rank;
}
void nextPermutation(vector<int>& nums) {
    int n = nums.size();
    int i = n - 2;
    while (i >= 0 && nums[i] >= nums[i + 1]) {
        i--;
    }
    if (i >= 0) {
        int j = n - 1;
        while (j > i && nums[j] <= nums[i]) {
            j--;
        }
        swap(nums[i], nums[j]);
    }
    reverse(nums.begin() + i + 1, nums.end());
}
 
