#include<bits/stdc++.h>
using namespace std;
void quicksort(int arry[],int low,int high)
{
    int i=low;
    int j=high;
    if(i>=j) {return ;}
    int temp =arry[low];
    while(i!=j)
    {
        while (arry[j]>=temp&&i<j)
        {
            j--;
        }
        while(arry[i]<=temp&&i<j)
        {
            i++;
        }
        if(i<j)
        {
            swap(arry[i],arry[j]);
        }
    }
    swap(arry[low],arry[i]);
    quicksort(arry,low,i-1);
    quicksort(arry,i+1,high);

}
