// 递归计算深度
int getDepth(const string &s) {
    if (idx >= s.size()) return 0;
    if (s[idx] == '#') {
        idx++;  // 跳过空节点
        return 0;
    }
    idx++;  // 当前非空节点，先跳过自己
    int left = getDepth(s);
    int right = getDepth(s);
    return max(left, right) + 1;
}

