#include <iostream>
#include <string>
#include <algorithm>  // 用于max函数
using namespace std;

// 递归计算二叉树深度：
// s: 前序遍历序列，index: 当前遍历到的位置（引用传递，保证递归中共享同一个索引）
int getDepth(const string &s, int &index) {
    // 终止条件1：当前节点是空节点（#），深度为0
    if (s[index] == '#') {
        index++;  // 索引后移，处理下一个字符
        return 0;
    }
    
    // 非空节点：先处理当前节点（索引后移），再递归算左、右子树深度
    index++;  // 跳过当前非空节点（根），准备处理左子树
    int left_depth = getDepth(s, index);  // 递归计算左子树深度
    int right_depth = getDepth(s, index); // 递归计算右子树深度
    
    // 当前节点的深度 = 左右子树深度的最大值 + 1（当前节点本身）
    return max(left_depth, right_depth) + 1;
}

int main() {
    ios::sync_with_stdio(false);  // 加速输入，处理长序列
    cin.tie(nullptr);
    
    int m;  // 测试用例数
    cin >> m;
    // 循环处理每个测试用例
    while (m--) {
        string s;  // 存储前序遍历序列
        cin >> s;
        int index = 0;  // 初始化遍历索引为0（从第一个字符开始）
        int depth = getDepth(s, index);  // 计算深度
        cout << depth << endl;  // 输出结果
    }
    return 0;
}

