#include<bits/stdc++.h>
using namespace std;

const int N = 100010;
int idx;
string s;
char tree[N];

void build(int cur) {
    if(idx >= s.length()) return;
    if(s[idx] == '#') {
        tree[cur] = '#';
        idx++;
        return;
    }
    tree[cur] = s[idx];
    idx++;
    build(cur * 2 + 1);  // 左孩子
    build(cur * 2 + 2);  // 右孩子
}

bool isCompleteBinaryTree() {
    queue<int> q;
    q.push(0);
    bool meetNull = false;
    
    while(!q.empty()) {
        int cur = q.front();
        q.pop();
        
        // 如果当前节点是空节点
        if(tree[cur] == '#' || tree[cur] == '\0') {
            meetNull = true;
        } else {
            // 如果之前已经遇到过空节点，现在又遇到非空节点，则不是完全二叉树
            if(meetNull) {
                return false;
            }
            // 将左右孩子加入队列（无论是否为空）
            q.push(cur * 2 + 1);
            q.push(cur * 2 + 2);
        }
    }
    return true;
}

