#include <iostream>
#include <queue>
#include <string>
using namespace std;

struct TreeNode {
    char val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(char c) : val(c), left(nullptr), right(nullptr) {}
};

int idx;  // 全局索引，用于递归建树

TreeNode* buildTree(const string& s) {
    if (idx >= s.length() || s[idx] == '#') {
        idx++;
        return nullptr;
    }
    TreeNode* node = new TreeNode(s[idx]);
    idx++;
    node->left = buildTree(s);
    node->right = buildTree(s);
    return node;
}

bool isCompleteTree(TreeNode* root) {
    if (!root) return true;
    queue<TreeNode*> q;
    q.push(root);
    bool meetNull = false;
    while (!q.empty()) {
        TreeNode* cur = q.front(); q.pop();
        if (!cur) {
            meetNull = true;
        } else {
            if (meetNull) return false;  // 之前遇到过空，现在遇到非空，不是完全二叉树
            q.push(cur->left);
            q.push(cur->right);
        }
    }
    return true;
}

int main() {
    string s;
    while (cin >> s) {
        idx = 0;
        TreeNode* root = buildTree(s);
        if (isCompleteTree(root)) {
            cout << "Yes\n";
        } else {
            cout << "No\n";
        }
    }
    return 0;
}

