	newNode->data = *s;
	T = newNode;

	char* left = CreateTree(T->lchild,s+1);
	char* right = CreateTree(T->rchild,left);
	
	return right;
	
}
bool isCompleteTree(BiTree root) {
    if (root == nullptr) return true;
    
    queue<BiNode*> q;
    q.push(root);
    bool flag = false;  // 标记是否遇到了空节点
    
    while (!q.empty()) {
        BiNode* node = q.front();
        q.pop();
        
        if (node == nullptr) {
            flag = true;  // 遇到了空节点
        } else {
            // 如果之前已经遇到了空节点，现在又遇到了非空节点，说明不是完全二叉树
            if (flag) return false;
            
            // 无论左右孩子是否为空，都入队
            q.push(node->lchild);
            q.push(node->rchild);
        }
    }
    return true;
}
void deleteTree(BiTree T) {
    if (T == nullptr) return;
    deleteTree(T->lchild);
    deleteTree(T->rchild);
    delete T;
}
int main(){
	char s[2000];
	while(cin>>s){
		int count = 0;
		for(int i = 0;i<strlen(s);i++){
			if(s[i] != '#'){
				count++;
			}
		}
		BiTree T = nullptr;
		CreateTree(T,s);
		
		if(isCompleteTree(T)){
			cout<<"Yes"<<endl;
		}else{
			cout<<"No"<<endl;
		}
		deleteTree(T);
	}
	return 0;

}

#include<iostream>
