using namespace std;

string tree;
int idx;
bool nodes[10000];
int max_idx;

void builTree(int pos){
    if(idx >=tree.length()){
        return;
    } 
    char ch = tree[idx++];
    if(ch =='#') {
        return;
    }
    nodes[pos]= true;
    max_idx = max(max_idx,pos);
    builTree(pos*2);
    builTree(pos*2+1);
}

bool isCompTree(){
    for(int i = 1; i < max_idx; i++){
        if(!nodes[i]){
            return false;
        }
    }return true;
}

