    while (cin >> tree){
        idx = 0;
        max_idx = 0;
        memset(nodes, 0, sizeof(nodes));
        builTree(1);
        if(isCompTree()){
            cout << "Yes" <<endl;
        }else{
            cout << "No" << endl;
        }
    }return 0 ;
}

