cout<<"\n";
cout<<"\n";
cout<<"RFC 959                                                     October 1985\n";
cout<<"File Transfer Protocol\n";
cout<<"\n";
cout<<"\n";
cout<<"      In particular, the following new optional commands are included in\n";
