cout<<"\n";
cout<<"   2.2.  TERMINOLOGY\n";
cout<<"\n";
cout<<"      ASCII\n";
cout<<"\n";
cout<<"         The ASCII character set is as defined in the ARPA-Internet\n";
cout<<"         Protocol Handbook.  In FTP, ASCII characters are defined to be\n";
