cout<<"\n";
cout<<"      access controls\n";
cout<<"\n";
cout<<"         Access controls define users' access privileges to the use of a\n";
cout<<"         system, and to the files in that system.  Access controls are\n";
cout<<"         necessary to prevent unauthorized or accidental use of files.\n";
cout<<"         It is the prerogative of a server-FTP process to invoke access\n";
cout<<"         controls.\n";
cout<<"\n";
cout<<"      byte size\n";
cout<<"\n";
cout<<"         There are two byte sizes of interest in FTP:  the logical byte\n";
