cout<<"\n";
cout<<"      EOR\n";
cout<<"\n";
cout<<"         The end-of-record condition that defines the end of a record\n";
cout<<"         being transferred.\n";
cout<<"\n";
cout<<"      error recovery\n";
cout<<"\n";
cout<<"         A procedure that allows a user to recover from certain errors\n";
cout<<"         such as failure of either host system or transfer process.  In\n";
cout<<"         FTP, error recovery may involve restarting a file transfer at a\n";
