cout<<"\n";
cout<<"\n";
cout<<"\n";
cout<<"Postel & Reynolds                                               [Page 4]\n";
cout<<"\n";
cout<<"\n";
cout<<"RFC 959                                                     October 1985\n";
cout<<"File Transfer Protocol\n";
cout<<"\n";
cout<<"\n";
cout<<"      FTP commands\n";
cout<<"\n";
