cout<<"\n";
cout<<"      NVT\n";
cout<<"\n";
cout<<"         The Network Virtual Terminal as defined in the Telnet Protocol.\n";
cout<<"\n";
cout<<"      NVFS\n";
cout<<"\n";
cout<<"         The Network Virtual File System.  A concept which defines a\n";
cout<<"         standard network file system with standard commands and\n";
