cout<<"\n";
cout<<"\n";
cout<<"\n";
cout<<"\n";
cout<<"Postel & Reynolds                                               [Page 6]\n";
cout<<"\n";
cout<<"\n";
cout<<"RFC 959                                                     October 1985\n";
cout<<"File Transfer Protocol\n";
cout<<"\n";
cout<<"\n";
cout<<"      user\n";
cout<<"\n";
cout<<"         A person or a process on behalf of a person wishing to obtain\n";
