#include <iostream>
#include <vector>
#include<queue>
using namespace std;
struct Node {
	char data;
	Node *left,*right;
	Node(char c) : data(c), left(nullptr), right(nullptr) {}
};
Node* buildTree(const string& s, int& index) {
	if (index >= s.length() || s[index] == '#') {
		index++;
		return nullptr;
	}
	Node* root =new Node(s[index]);
	index++;
	root->left=buildTree(s,index);
	root->right=buildTree(s,index);
	return root;
}
int  checkBalance(Node* root) {
	if(!root) return 0;
	int leftHeight=checkBalance(root->left);
	if(leftHeight==-1) return -1;
	int rightHeight =checkBalance(root->right);
	if (rightHeight == -1) return -1;
	if (abs(leftHeight - rightHeight) > 1) {
		return -1;
	}
	return max(leftHeight,rightHeight)+1;
}
int main() {
	string s;
	while (cin >> s) {
		int index=0;
		Node* root = buildTree(s,index);
		if (checkBalance(root) != -1) {
			cout<<"Yes"<<endl;
		}
		else {
			cout<<"No"<<endl;
		}
	}
	return 0;
}

#include<bits/stdc++.h>

using namespace std;

const int N=1e6+10;

struct Tnode
{
    char data;
    int h=1;
    Tnode *l=NULL,*r=NULL;
};
typedef Tnode* T;

int get_h(T root)
{
    if(root==NULL) return 0;
    else return root->h;
}

int get_bal(T root)
{
    if(root==NULL) return 0;
    return get_h(root->l)-get_h(root->r);
}

void update(T &root)
{
    if(root==NULL) return;
    root->h=max(get_h(root->l),get_h(root->r))+1;
}

int x=0;

T insert(string &op)
{
    if(x>op.size() or op[x]=='#') {
        x++;
        return NULL;
    }
    T root=new Tnode;
    root->data=op[x];
    x++;
    root->l =insert(op);
    //update(root->l);
    //cout << x << ' ' << op[x] << endl;
    root->r =insert(op);
    //update(root->r);
    update(root);
    return root;
}

void bianli(T &root,string op)
{
    if(root==NULL) return;
    cout << op << root->data << endl;
    bianli(root->l,"    "+op);
    if(root->l==NULL and root->r!=NULL)
    {
        cout << "    "+op << "#" << endl;
    }
    bianli(root->r,"    "+op);
    if(root->l!=NULL and root->r==NULL)
    {
        cout << "    "+op << "#" << endl;
    }
}

bool is(T root)
{
    if(root==NULL) return true;
    if(abs(get_bal(root))>=2) return 0;
    return (is(root->l) and (is(root->r)));
}

int main()
{
    string op;
    
    while(cin >> op)
    {
        x=0;
        T root=NULL;
        root=insert(op);
    
        if(is(root)) cout << "Yes"<< endl;
        else cout << "No" << endl;
    }
    
    return 0;
}

