const int N = 2e5 + 10;
char a[N];
int ls[N], rs[N], idx;
int dep[N];

string s; bool f;
void dfs(int u)
{
	a[u] = s[idx++];
	if (a[u] == '#')
		return;
	ls[u] = idx; dfs(idx);
	rs[u] = idx; dfs(idx);
}

void dfs2(int u)
{
	int maxn = 0;
	if (a[ls[u]] != '#')
	{
		dfs2(ls[u]); 
		maxn = max(maxn, dep[ls[u]]);
	}
	if (a[rs[u]] != '#')
	{
		dfs2(rs[u]);
		maxn = max(maxn, dep[rs[u]]);
	}
	dep[u] = maxn + 1;
	if (abs(dep[ls[u]] - dep[rs[u]]) > 1)
		f = false;
}

