bool isbalanced;

int dfs(){
    if(s[idx]=='#'){
        idx++;
        return 0;
    }
    idx++;
    int ld=dfs();
    int rd=dfs();
    
    if(abs(ld-rd)>1) isbalanced=false;
    return max(ld,rd)+1;
}

