char move_letter(char a, int b){
	b = a+b;
	if (is_schar(a)){
		if (b > 'z'){
			b-=26;
		}else if(b < 'a'){
			b+=26;
		}
		return (char)b;
	}else if(is_bchar(a)){
		if (b > 'Z'){
			b-=26;
		}else if(b < 'A'){
			b+=26;
		}
		return (char)b;
	}else return 0;
}

