/* 代码头注释：说明算法名称和关键技巧 */
// 算法名称：区间动态规划（Interval DP）
// 关键技巧：四边形不等式优化，将时间复杂度从 O(n^3) 优化到 O(n^2)

#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const int INF = 0x3f3f3f3f;
const int MAXN = 1005;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> a(n + 1);
    vector<int> prefix(n + 1, 0);
    for (int i = 1; i <= n; ++i) {
        cin >> a[i];
        prefix[i] = prefix[i - 1] + a[i];
    }

    vector<vector<int>> dp(n + 1, vector<int>(n + 1, INF));
    vector<vector<int>> opt(n + 1, vector<int>(n + 1, 0));

    for (int i = 1; i <= n; ++i) {
        dp[i][i] = 0;
        opt[i][i] = i;
    }

    for (int l = 2; l <= n; ++l) {
        for (int i = 1; i <= n - l + 1; ++i) {
            int j = i + l - 1;
            // [FIX] 增加边界检查，确保k在[i, j-1]范围内
            for (int k = max(opt[i][j - 1], i); k <= min(opt[i + 1][j], j - 1); ++k) {
                int cost = dp[i][k] + dp[k + 1][j] + prefix[j] - prefix[i - 1];
                if (cost < dp[i][j]) {
                    dp[i][j] = cost;
                    opt[i][j] = k;
                }
            }
        }
    }

    cout << dp[1][n] << endl;

    return 0;
}

