const int MAX_NUM = 20001;
int maxPrime[MAX_NUM]; // 存每个数的最大质因数

// 筛法预处理：记录每个数的最大素因子
void computeMaxPrime() {
    for (int i = 2; i < MAX_NUM; ++i) {
        if (maxPrime[i] == 0) { // i 是质数
            for (int j = i; j < MAX_NUM; j += i) {
                maxPrime[j] = i; // 因为 i 是当前质因数，覆盖掉较小的质因子
            }
        }
    }
}

int main() {
    int N;
    cin >> N;

    computeMaxPrime(); // 预处理最大质因子

    int maxPrimeValue = 0;
    int answer = -1;

    for (int i = 0; i < N; ++i) {
        int num;
        cin >> num;
        int mp = maxPrime[num];
        if (mp > maxPrimeValue) {
            maxPrimeValue = mp;
            answer = num;
        }
    }

    cout << answer << endl;
    return 0;
}

