double tempmin[MAXN],tempmax[MAXN];
int cnt[MAXN];

double max_gap()
{
    //寻找最小值和最大值
    double maxx=a[0],minx=a[0];
    for(int i=1;i<=n-1;i++)
    {
        maxx=max(maxx,a[i]);
        minx=min(minx,a[i]);
    }
    //建立桶,让每个桶的最小值初始为最大值,每个桶的最大值初始为最小值
    for(int i=0;i<=n-1;i++)
    {
        tempmin[i]=maxx;
        tempmax[i]=minx;
    }
    double len=(maxx-minx)/(n-1);//平均距离

    for(int i=0;i<=n-1;i++)
    {
        int id=(int)((a[i]-minx)/len);
        //cout << id << "***" << endl;
        tempmin[id]=min(tempmin[id],a[i]);
        tempmax[id]=max(tempmax[id],a[i]);
        cnt[id]++;
    }
    double res=0;
    double l=tempmax[0];
    for(int i=1;i<=n-1;i++)
    {
        if(cnt[i]!=0)
        {
            res=max(res,tempmin[i]-l);
            l=tempmax[i];
        }
    }

    return res;
}

