typedef struct Er{
    char data;
    struct Er *rc;
    struct Er *kc;

}Er,*Ershu;
void back(Ershu tree){
    if(tree!=NULL){
        back(tree->kc);
        back(tree->rc);
        if(tree->data=='#') 
        printf(" ");
        else printf("%c",tree->data);
    }
}
void level(Ershu tree)
{
    queue<Er*> p;
    p.push(tree);
    while(!p.empty())
    {
        Ershu t=p.front();
        p.pop();
        if(t!=NULL)
        {
            if(tree->data!='#')
            printf("%c",t->data);
            p.push(t->kc);
            p.push(t->rc);
        }
    }
}
void creat(Ershu * tree,char *s,char *s1){
    
    if(strlen(s1)==0)
    {
        (*tree)=NULL;
        return;
    }
    char c;
    c=s[0];
    int temp;
    for(int i=0;i<strlen(s1);i++)
    {
        if(s1[i]==c)
        {
            temp=i;
        }
    }
    char k_y1[2000]={'\0'};
    char k_y2[2000]={'\0'};
    char r_y1[2000]={'\0'};
    char r_y2[2000]={'\0'};

    for(int i=0;i<temp;i++){
        k_y2[i]=s1[i];
        k_y1[i]=s[i+1];
    }
    for(int i=0;i<strlen(s1)-temp-1;i++){
        r_y1[i]=s[i+temp+1];
        r_y2[i]=s1[i+temp+1];
    }
    (*tree)=(Ershu)malloc(sizeof(Er));
    if((*tree)!=NULL){
        (*tree)->data=c;
        creat(&((*tree)->kc),k_y1,k_y2);
        creat(&((*tree)->rc),r_y1,r_y2);
    }
}
