// 计算杨辉三角
vector<vector<long long>> generatePascalsTriangle(int n) {
    vector<vector<long long>> triangle(n);
    for (int i = 0; i < n; i++) {
        triangle[i].resize(i+1, 1);
        for (int j = 1; j < i; j++) {
            triangle[i][j] = triangle[i-1][j-1] + triangle[i-1][j];
        }
    }
    return triangle;
}

// 计算数字位数
int numWidth(long long x) {
    int w = 0;
    do {
        w++;
        x /= 10;
    } while (x);
    return w;
}

