int hwidth(int n) {
    int maxw = 1;
    int k = (n - 1) / 2;
    for (int i = 1; i <= k; i++) 
        maxw = maxw * (n - i) / i;
    int wid = 0;
    while (maxw) {
        wid++;
        maxw /= 10;
    }
    return wid;
}

