// 计算数字的位数
int getDigitCount(int num) {
    if (num == 0) return 1;
    int cnt = 0;
    while (num > 0) {
        cnt++;
        num /= 10;
    }
    return cnt;
}

// 打印杨辉三角
void PrintYHTriangle(int n) {
    if (n <= 0) return;

    // 用二维数组存储杨辉三角，避免动态内存分配
    int triangle[31][31] = {0}; // n最大为30，数组足够大

    // 填充杨辉三角
    for (int i = 1; i <= n; ++i) {
        triangle[i][1] = 1; // 每行第一个元素为1
        triangle[i][i] = 1; // 每行最后一个元素为1
        for (int j = 2; j < i; ++j) {
            triangle[i][j] = triangle[i-1][j-1] + triangle[i-1][j];
        }
    }

    // 找到最大数的位数，确定输出宽度
    int maxNum = 1;
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= i; ++j) {
            if (triangle[i][j] > maxNum) {
                maxNum = triangle[i][j];
            }
        }
    }
    int maxLen = getDigitCount(maxNum);

    // 按格式输出
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= i; ++j) {
            if (j == 1) {
                // 第一个数前面没有空格
                cout << triangle[i][j];
            } else {
                // 后续每个数的宽度为最大宽度+1
                cout << setw(maxLen + 1) << triangle[i][j];
            }
        }
        cout << endl;
    }
}

int main() {
    int num;
    while (cin >> num) {
        PrintYHTriangle(num);
        cout << endl; // 每组输出间用换行分隔
    }
    return 0;
}

#include <stdio.h>

// 计算组合数 C(n, k)
long long C(int n, int k) {
    if (k > n - k) k = n - k;
    long long res = 1;
    for (int i = 1; i <= k; ++i)
        res = res * (n - i + 1) / i;
    return res;
}

// 获取最大数字的位数
int getWidth(int n) {
    long long maxNum = C(n - 1, (n - 1) / 2);
    int width = 0;
    while (maxNum > 0) {
        width++;
        maxNum /= 10;
    }
    return width + 1;  // 加1表示数字间空格
}

// 打印杨辉三角
void printYangHui(int n) {
    int width = getWidth(n);
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j <= i; ++j) {
            long long num = C(i, j);
            if (j == 0)
                printf("%lld", num);
            else
                printf("%*lld", width, num);
        }
        printf("\n");
    }
}

int main() {
