    while (scanf("%d", &n) != EOF) {
        if (!first) printf("\n");
        printYangHui(n);
        first = 0;
    }
    return 0;
}

#include <iostream>
#include <string>
#include <stack>
using namespace std;

int main() {
    string input;
    getline(cin, input); // 读取整行输入

    stack<char> buffer; // 使用栈作为缓冲区来处理字符

    // 遍历输入字符串中的每个字符
    for (char ch : input) {
        // 如果遇到'#'，则清空缓冲区
        if (ch == '#') {
            while (!buffer.empty()) {
                buffer.pop();
            }
        } else if (ch == '@') {
            // 如果栈非空且遇到'@'，则删除一个字符
            if (!buffer.empty()) {
                buffer.pop();
            }
        } else {
            // 其他情况下，将字符压入栈中
            buffer.push(ch);
        }
    }

    string output;
    // 从栈中取出所有字符，构建输出字符串
    while (!buffer.empty()) {
        output = buffer.top() + output; // 此处注意要将字符加在输出字符串的前面
        buffer.pop();
    }

    cout << output << endl; // 输出结果

    return 0;
}

