using namespace std;
#define MAXSIZE 500
typedef char datatype;
typedef struct 
{
	datatype data[MAXSIZE];
	int top;
}SeqStack;
SeqStack *InitSeqStack()
{
	SeqStack *s;
	s=(SeqStack *)malloc(sizeof(SeqStack));
	s->top=-1;
	return s;
}
int EmptySeqStack(SeqStack *s)
{
	if(s->top==-1)
	{
		return 1;
	}
	else
	{
		return 0;
	}
}
void PrintSeqStack(SeqStack *s)
{
	int i;
	for(i=0;i<=s->top;i++)
	{
		printf("%c",s->data[i]);
	}
	printf("\n");
}
int PushSeqStack(SeqStack *s,datatype x)
{
	if(s->top==MAXSIZE-1)
	{
		return 1;
	}
	else
	{
		s->top++;
		s->data[s->top]=x;
		return 0;
	}
}
int PopSeqStack(SeqStack *s,datatype &x)
{
	if(EmptySeqStack(s))
	{
		return 1;
	}
	else
	{
		x=s->data[s->top];
		s->top--;
		return 0;
	}
}
datatype GetSeqStack(SeqStack *s)
{
	if(EmptySeqStack(s))
	{
		return '1';
	}
	else
	{
		return (s->data[s->top]);
	}
}
int ClearSeqStack(SeqStack *s)
{
	s->top=-1;
	return 1;
} 
int DestorySeqStack(SeqStack *s)
{
	s->top=-1;
	free(s);
	return 1;
}
