// 递归函数，返回将n只羊从A羊圈移动到C羊圈所需的最小步骤数
int moveSheep(int n) {
    if (n == 1) {
        return 1;  // 只有一只羊时，只需要一步
    }
    // 如果有n只羊，步骤数等于两部分的总和：将n-1只羊移到中转羊圈 + 将1只羊移到目标羊圈 + 将n-1只羊从中转羊圈移到目标羊圈
    return 2 * moveSheep(n - 1) + 1;
}

int main() {
    int N;
    cin >> N;  // 输入羊的个数
    cout << moveSheep(N) << endl;  // 输出最少步骤数
    return 0;
}

