int chi(int A[],int begin,int number,int B)
{
    if(A[number]==B)
    {
        return 1;
    }  
    if(B <=0)
    {
        return 0;
    }      
    if(number==begin)
    {
        if(A[begin]==B)
        {
            return 1;
        }    
        else
        {
            return 0;
        }    
    }    
    else
    {
        int sum=0;
        for(int j=number-1;j>=0;j--)
        {
            
            if(chi(A,begin,j,B-A[number])==1)
            {
                sum=1;
                break;
            }    
        }
        if(sum==1)
        {
            return 1;
        }          
        else
        {
            return 0;
        }    
    }    
}    
