using namespace std;
int solve(int n)
{
	int ans = 1, i;					// ans = 1初始表示n = n的情况
	for (i = 2; i * i < n; i++)		// 因子乘因子小于n
		if (n % i == 0)				// i 是 n的因子, n / i也是n的因子
			ans += solve(i) + solve(n / i);
	if (i * i == n)					// i是n的因子, 并且i * i == n时只有这一种情况, 左右交换也是一种
		ans += solve(i);
	return ans;
}

