    while (m--) {
        int n;
        cin >> n;
        vector<int> t(n);
        for (int i = 0; i < n; ++i) {
            cin >> t[i];
        }
        
        // 短作业优先：升序排序服务时间
        sort(t.begin(), t.end());
        
        // 计算总等待时间
        long long total_wait = 0;
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            total_wait += current_sum;
            current_sum += t[i];
        }
        
        // 计算平均等待时间的整数部分
        int avg = total_wait / n;
        cout << avg << endl;
    }
    return 0;
}

