struct Customer {
    int id;
    int time;
};

bool compare(const Customer &a, const Customer &b) {
    return a.time < b.time;
}

int main() {
    int m;
    cin >> m;
    while (m--) {
        int n;
        cin >> n;
        Customer customers[1005];
        for (int i = 1; i <= n; i++) {
            cin >> customers[i].time;
            customers[i].id = i;
        }
        sort(customers + 1, customers + 1 + n, compare);
        int sum = 0;
        for (int i = 1; i <= n; i++) {
            sum += customers[i].time * (n - i);
        }
        int avg = sum / n;
        cout << avg << endl;
    }
    return 0;
}

