    int t,a,b,c,d,e,i;
    while(scanf("%s",str)!=EOF)
    {
        if(str[0]=='0') return 0;
        t=strlen(str);
        while(t>3)
        {
            d=(str[t-1]-'0')*5;
            c=(str[t-2]-'0');
            b=(str[t-3]-'0')*10;
            a=(str[t-4]-'0')*100;
            e=a+b+c-d;
            str[t-2]=e%10+'0';
            str[t-3]=e/10%10+'0';
            str[t-4]=e/100+'0';
            t--;
        }
        for(e=0,i=0;i<=t-1;i++)
        {
            e=e*10;
            e=e+(str[i]-'0');
        }
        if(e%17==0)
        printf("1\n");
