#include <unordered_map>

int main() {
    int n;
    std::cin >> n;

    // 用于存储每个数及其出现的次数
    std::unordered_map<int, int> numCount;

    // 读取输入的自然数
    for (int i = 0; i < n; ++i) {
        int num;
        std::cin >> num;
        // 如果该数已经在 map 中，对应次数加 1
        // 如果不在，会自动插入并初始化为 0 后再加 1
        ++numCount[num];
    }

    // 将所有不同的数存储到一个向量中
    std::vector<int> uniqueNums;
    for (const auto& pair : numCount) {
        uniqueNums.push_back(pair.first);
    }

    // 对不同的数进行排序
    std::sort(uniqueNums.begin(), uniqueNums.end());

    // 按从小到大的顺序输出每个数及其出现的次数
    for (int num : uniqueNums) {
        std::cout << num << " " << numCount[num] << std::endl;
    }

    return 0;
}

