#include <iostream>
#include <vector>

using namespace std;

// 题目要求的模数
const int MOD = 9901;
// 差值范围是 -1000 到 1000，加上偏移量 1000 使下标变为非负
const int OFFSET = 1000;
// 差值最大范围 2000，稍微开大一点防止越界
const int MAX_DIFF = 2005;
const int MAX_N = 1005;

// dp[i][d] 表示以 A[i] 结尾，公差为 (d - OFFSET) 的长度 >= 2 的等差数列个数
int dp[MAX_N][MAX_DIFF];
int A[MAX_N];

int main() {
    // 优化 I/O 速度
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N;
    if (!(cin >> N)) return 0;

    for (int i = 0; i < N; ++i) {
        cin >> A[i];
    }

    // 初始化答案为 N，因为长度为 1 的单独数字也算等差数列
    int ans = N;

    // 外层枚举结尾元素 i
    for (int i = 0; i < N; ++i) {
        // 内层枚举 i 之前的元素 j
        for (int j = 0; j < i; ++j) {
            // 计算公差，并加上偏移量
            int diff = A[i] - A[j] + OFFSET;
            
            // 此时以 i 结尾，公差为 diff 的新增方案数 = 
            // (以 j 结尾该公差的方案数) + (j, i 这一对新组成的长度为2的序列)
            // dp[j][diff] 代表以 j 结尾长度 >= 2 的序列，接上 i 后变成长度 >= 3
            // 1 代表 {A[j], A[i]} 这个长度为 2 的序列
            int count = (dp[j][diff] + 1) % MOD;
            
            // 更新 dp 表
            dp[i][diff] = (dp[i][diff] + count) % MOD;
            
            // 累加到总答案中
            ans = (ans + count) % MOD;
        }
    }

    cout << ans << endl;

    return 0;
}

