using namespace std;
#define mode 9901
int f(vector<int> & a,int n)
{
    vector<vector<int>> dp(n,vector<int>(2000+1,0));
    int res=0;
    for(int i=0;i<n;i++)
    {
        for(int j=0;j<i;j++)
        {
            int d=a[i]-a[j];
            d=d+1000;
            dp[i][d]+=dp[j][d]+1;
            res+=dp[j][d]+1;
        }
        res+=1;
    }
    return res%mode ;
}
