void solve(int n){
	vector<vector<int>> vt(n);
	for(int i=0;i<n;i++){
		vector<int> newvt(n);
		vt[i]=newvt;
	}
	int cnt=1;
	for(int i=0;i<n;i++){
		vt[0][i]=cnt;
		cnt++;
	}
	for(int i=1;i<n;i++){
		vt[i][n-1]=cnt;
		cnt++;
	}
	for(int i=1;i<n;i++){
		vt[n-1][n-1-i]=cnt;
		cnt++;
	}
	for(int i=1;i<n-1;i++){
		vt[n-1-i][0]=cnt;
		cnt++;
	}
	for(int i=0;i<n;i++){
		for(int j=0;j<n;j++){
			if(vt[i][j]==0){
				cout<<setw(3)<<" ";
			}
			else{
				cout<<setw(3)<<vt[i][j];
			}
		}
		cout<<endl;
	}
}

int main(){
	int n;
	while(cin>>n){
		if(n==0){
			break;
		}
		solve(n);
	}
	return 0;
}

