    int prime[4]={2,3,5,7};
    for(i=2;i<=5842;i++)
    {
        num[i]=2000000001;
        for(j=0;j<4;j++)
            for(k=i-1;k>=1;k--)
            {
                if(num[k]*prime[j]<=num[i-1])
                    break;
                if(num[k]*prime[j]<num[i])
                    num[i]=num[k]*prime[j];
            }
    }
