        low=n%base;
        if(cur<1)
        {
            count1+=high*base;
        }
        else if(cur==1)
        {
            count1+=high*base+low+1;
        }
        else 
        {
            count1+=(high+1)*base;
        }
        base*=10;
    }
    return count1;
}
