int func(int n){
    int factor = 1;
    int icount = 0;
    int ihigh = 0;
    int icurrent = 0;
    int ilow = 0;
    while(n/factor){
        ilow = n%factor;
        icurrent = n/factor%10;
        ihigh = n/factor/10;
        switch(icurrent){
            case 0:icount += ihigh * factor;break;
            case 1:icount += ihigh * factor+ilow+1;break;
            default:icount += (ihigh+1)*factor;break;
        }
        factor *= 10;
    }
    return icount;
}

