using namespace std;


void solve(int n){
	vector<int> v;
	vector<int> dp;
	vector<int> s;
	int l=-1;
	int flag=0;
	
	for(int i=0;i<n;i++){
		int a=0;
		cin>>a;
		v.push_back(a);
		if(a>=0){
			flag=1;
		}
	}
	
	if(flag==0){
		cout<<0<<" "<<-1<<" "<<-1<<endl;
		return;
	}
	
	dp.push_back(max(-1,v[0]));
	if(v[0]>=0){
		l=0;
	}
	s.push_back(l);
	
	for(int i=1;i<n;i++){
		if(v[i]>dp[i-1]+v[i]){
			l=i;
		}
		dp.push_back(max(dp[i-1]+v[i],v[i]));
		s.push_back(l);
	}
	int ans=-1;
	int cnt=-1;
	for(int i=0;i<n;i++){
		if(dp[i]>ans){
			cnt=i;
			l=s[i];
		}
		ans=max(ans,dp[i]);
	}

	cout<<ans<<" "<<l<<" "<<cnt<<endl;
}

int main(){
	int n;
	while(cin>>n){
		solve(n);
	}
	return 0;
}

