int main() {
    ios::sync_with_stdio(false);  // 加速输入输出，处理大数据量时必须
    cin.tie(nullptr);

    int n;
    // 循环读取多组测试数据，直到输入结束
    while (cin >> n) {
        vector<int> nums(n);
        bool all_negative = true;  // 标记是否所有数都是负数
        for (int i = 0; i < n; ++i) {
            cin >> nums[i];
            if (nums[i] >= 0) {
                all_negative = false;
            }
        }

        // 如果所有数都是负数，直接输出0 -1 -1
        if (all_negative) {
            cout << "0 -1 -1\n";
            continue;
        }

        // Kadane算法核心逻辑
        int current_sum = 0;       // 当前子序列的和
        int max_sum = INT_MIN;     // 全局最大和，初始化为最小整数
        int current_start = 0;     // 当前子序列的起始位置（数组下标）
        int max_start = 0;         // 最大和子序列的起始位置（数组下标）
        int max_end = 0;           // 最大和子序列的结束位置（数组下标）

        for (int i = 0; i < n; ++i) {
            // 如果当前和加上当前数比当前数本身小，说明重新开始一个子序列更优
            if (current_sum + nums[i] < nums[i]) {
                current_sum = nums[i];
                current_start = i;  // 重置当前子序列的起始位置
            } else {
                current_sum += nums[i];
            }

            // 更新全局最大和及对应的起止位置
            if (current_sum > max_sum) {
                max_sum = current_sum;
                max_start = current_start;
                max_end = i;
            }
        }

        // 题目要求的位置是从1开始计数，所以要+1
        cout << max_sum << " " << max_start << " " << max_end<< "\n";
    }

    return 0;
}

