        int temp_start = 0;       // 临时起点（记录当前子数组的起点）
        bool has_positive = false; // 标记是否存在正数

        for (int i = 0; i < n; ++i) {
            current_sum += nums[i];

            // 情况1：当前和>最大和 → 更新最大和及位置
            if (current_sum > max_sum) {
                max_sum = current_sum;
                start = temp_start;
                end = i;
                has_positive = true; // 存在正数
            }
            // 情况2：当前和<0 → 重置当前和，起点移到下一个位置
            else if (current_sum < 0) {
                current_sum = 0;
                temp_start = i + 1;
            }
            // 情况3：当前和=最大和 → 保持第一个子数组（不更新）
        }

        // 输出结果：全负数时输出0 -1 -1；否则输出最大和+起止位置（从1开始）
        if (!has_positive) {
            cout << "0 -1 -1\n";
        } else {
            cout << max_sum << " " << start << " " << end << "\n";
        }
    }

    return 0;
}

