#include <stdio.h>
#include <stdlib.h>

#define error 0
#define OK 1
#define overflow 0

typedef int Status;

typedef struct{
    int data;
    struct LNode *next;
}LNode,*LinkList;

Status CreateList(LinkList *L,int n){
    LinkList p,q;
    (*L)=(LinkList)malloc(sizeof(LNode));
    if(!(*L))
        exit(overflow);
    (*L)->next=NULL;
    q=(*L);
    int i;
    for(i=0;i<n;i++){
        p=(LinkList)malloc(sizeof(LNode));
        if(!p)
            exit(overflow);
        scanf("%d",&p->data);
        p->next=NULL;
        q->next=p;
        q=p;
    }
    return OK;
}

Status ListInversion(LinkList *L){
    LinkList p1,p2,p3;
    p1=NULL;
    p2=(*L)->next;
    (*L)->next=NULL;
    while(p2){
        p3=p2->next;
        p2->next=p1;
        p1=p2;
        p2=p3;
    }
    (*L)->next=p1;
    return OK;
}

Status Show(LinkList *L){
    LinkList p;
    p=(*L)->next;
    if(!p)
        return error;
    while(p!=NULL){
        printf("%d ",p->data);
        p=p->next;
    }
    return OK;
}

