{
    LinkList L;
    int n;
    while(scanf("%d",&n)!=EOF){
        if(n==0)
            printf("list is empty\n");
        else{
            CreateList(&L,n);
            Show(&L);
            printf("\n");
            ListInversion(&L);
            Show(&L);
            printf("\n");
        }
   }
   return 0;
}

