#include <iostream>
#include <vector>

int reverseNumber(int num) {
    int reversed = 0;
    while (num > 0) {
        int digit = num % 10;
        if (digit == 6) digit = 9;
        else if (digit == 9) digit = 6;
        reversed = reversed * 10 + digit;
        num /= 10;
    }
    if (reversed < 10) {
        reversed *= 10;
    }
    return reversed;
}

int main() {
    int n;
    std::cin >> n;
    std::vector<int> numbers(n);

    for (int i = 0; i < n; ++i) {
        std::cin >> numbers[i];
        numbers[i] = reverseNumber(numbers[i]);
    }
    bool isIncreasing = true;
    for (int i = 1; i < n; ++i) {
        if (numbers[i] < numbers[i - 1]) {
            isIncreasing = false;
            break;
        }
    }

    int nextNumber;
    if (isIncreasing) {
        nextNumber = numbers[n - 1] + (numbers[n - 1] - numbers[n - 2]);
    } else {
        nextNumber = numbers[n - 1] - (numbers[n - 2] - numbers[n - 1]);
    }
    if (nextNumber == 90) {
        std::cout << "06";
    } else {
        nextNumber = reverseNumber(nextNumber);
        std::cout << nextNumber;
    }
    return 0;
}

