int cal(string s){
    int len=s.length();
    int all=0;
    int chushou=0;
    int mingzhong=0;
    for(int i=0;i<len;i++){

        if(s[i]>='1'&&s[i]<='9'){
            i++;
            if(s[i]=='N')chushou++;
            else all=all+s[i-1]-'0';chushou++;mingzhong++;
