void Convert(Node a[],int k){
    if(k==a->len-1) return ;
    int min1=9999999,min2=9999999;
    int loc1=-1,loc2=-1;
    for(int i=0;i<a->len+k;i++){
        if(a[i].data<min1&&a[i].parent==-1){
            min1=a[i].data;
            loc1=i;
        }
    }
    for(int i=0;i<a->len+k;i++){
        if(a[i].data<min2&&i!=loc1&&a[i].parent==-1){
            min2=a[i].data;
            loc2=i;
        }
    }
    if(loc1>loc2) swap(loc1,loc2);
    int sum=min1+min2;
    a[a->len+k].data=sum;
    a[a->len+k].lchild=loc1;
    a[a->len+k].rchild=loc2;
    a[loc1].parent=a->len+k;
    a[loc2].parent=a->len+k;
    Convert(a,k+1);
}
int  sum(Node a[],int n){
    int summ=0;
    for(int i=0;i<n;i++){
        int l=i;
        int t=0;
        while(1){
            if(a[l].parent==-1){
                break;
            }
            t++;
            l=a[l].parent;
        }
        summ+=a[i].data*t;
    }
    return summ;
}
