#include <cstdio>
#include <cstring>
#include <limits.h>
#include <algorithm>
#include <iostream>
using namespace std;

typedef char* HuffmanCode;

const int MAXN = 110;

typedef struct {
    int weight;
    int lchild, rchild, parent;
} HuffmanNode, *HuffmanTree;

void seletMin(HuffmanTree HT, int n, int &s1, int &s2) {
    int min = INT32_MAX;
    for (int i = 1; i <= n; ++i) {
        if(HT[i].parent == 0 && min > HT[i].weight) {
            min = HT[i].weight;
            s1 = i;
        }
    }

    min = INT32_MAX;
    for (int j = 1; j <= n; ++j) {
        if(HT[j].parent == 0 && min > HT[j].weight && j != s1) {
            min = HT[j].weight;
            s2 = j;
        }
    }

    if(s1 > s2) {
        swap(s1, s2);
    }

}

void HuffmanCoding(HuffmanTree &HT, HuffmanCode* &HC, int w[], int n) {
    // w存放n个字符的权值（均 > 0）,构造哈夫曼树HT，并求出n个字符的哈夫曼树编码HC
    if(n <= 1) return;
    int m = 2 * n - 1;  //m是因为需要（n - 1）次合并，所以总共要有（n + n - 1）个数据要存储
    //0号单元未用
    HT = new HuffmanNode[m + 1];

    //  初始权值存储
    for (int i = 1; i <= n; ++i) {
        HT[i].weight = w[i];
        HT[i].lchild = HT[i].rchild = HT[i].parent = 0;
    }

    //  要存储的合并后权值的初始化
    for (int i = n + 1; i <= m; ++i) {
        HT[i].lchild = HT[i].rchild = HT[i].parent = 0;
    }


    for (int i = n + 1; i <= m; ++i) { //建立哈夫曼树
        int s1, s2;
        //在HT[1~i-1]中选择parent为0且weight最小的两个结点，其序号分别为s1,s2
        seletMin(HT, i - 1, s1, s2);
        HT[s1].parent = HT[s2].parent = i;
        HT[i].lchild = s1;
        HT[i].rchild = s2;
        HT[i].weight = HT[s1].weight + HT[s2].weight;

    }
    //从叶结点到根你想求每个字符的哈夫曼编码
    HC = new HuffmanCode[n + 1];
    //分配n个字符编码的头指针向量([0]不用)
    char* cd = new char[n];//分配编码工作空间

    cd[n - 1] = '\0';//编码结束符

    for (int i = 1; i <= n; ++i) { //逐个字符求哈夫曼编码
        int star = n - 1;//编码结束位置
        for (int c = i, f = HT[i].parent; f != 0; c = f, f = HT[f].parent) {
            //从叶结点到根逆向求编码
            if(HT[f].lchild == c) {
                cd[--star] = '0';
            } else {
                cd[--star] = '1';
            }
        }
        //为第i个字符串编码分配空间（从star到(n - 1)，故长度为(n - 1 - start + 1)）
        HC[i] = new char[n - star];
        //从cd复制编码（串）到HC
        strcpy(HC[i], cd + star);
    }
    delete[] cd;//释放工作空间
}

int main() {
    HuffmanTree HT;
    HuffmanCode *HC;
    int n;
    int data[MAXN];

    while(scanf("%d", &n) != EOF) {
        for (int i = 1; i <= n; ++i) {
            scanf("%d", &data[i]);
        }

        HuffmanCoding(HT, HC, data, n);

        for (int j = 1; j <= n; ++j) {
            printf("%s\n", HC[j]);
        }

        delete(HT);
        delete(HC);
    }

    return 0;
}

#include <bits/stdc++.h>
using namespace std;
struct HuffmanNode
{
        char info;
        int weight;
        int parent,lchild,rchild;
        string huffmanCode;
};
struct HuffmanTree
{
        HuffmanNode *nodes;
        int leafnumber;
};
void CreateHuffmanTree(HuffmanTree &T,int leafnumber,int *weight)
{
        T.nodes=new HuffmanNode[leafnumber*2-1];
        T.leafnumber=leafnumber;
        for(int i=0;i<leafnumber;i++)
        {
                T.nodes[i].info='a'+i;
                T.nodes[i].weight=weight[i];
                T.nodes[i].parent=T.nodes[i].lchild=T.nodes[i].rchild=-1;
        }
        for(int i=0;i<leafnumber-1;i++)
        {
                int k1=-1;
                for(int j=0;j<leafnumber+i;j++)
                {
                        if(T.nodes[j].parent==-1)
                        {
                                if(k1==-1||(T.nodes[k1].weight>T.nodes[j].weight))
                                {
                                        k1=j;
                                }
                        }
                }
                T.nodes[k1].parent=-2;
                int k2=-1;
                for(int j=0;j<leafnumber+i;j++)
                {
                        if(T.nodes[j].parent==-1)
                        {
                                if(k2==-1||(T.nodes[k2].weight>T.nodes[j].weight))
                                {
                                        k2=j;
                                }
                        }
                }
                if(k1>k2) swap(k1,k2);
                T.nodes[i+leafnumber].weight=T.nodes[k1].weight+T.nodes[k2].weight;
                T.nodes[i+leafnumber].parent=-1;
                T.nodes[i+leafnumber].lchild=k1;
                T.nodes[i+leafnumber].rchild=k2;
                T.nodes[k1].parent=i+leafnumber;
                T.nodes[k2].parent=i+leafnumber;
        }
}
void CalcHuffmanCode(HuffmanTree &T)
{
        for(int i=0;i<T.leafnumber*2-1;i++)
        {
                T.nodes[i].huffmanCode="";
        }
        HuffmanNode root=T.nodes[T.leafnumber*2-2];
        queue<HuffmanNode> q;
        q.push(root);
        while(q.size())
        {
                HuffmanNode node = q.front();
                q.pop();
                if(node.lchild!=-1)
                {
                        T.nodes[node.lchild].huffmanCode=node.huffmanCode+"0";
                        q.push(T.nodes[node.lchild]);
                }

                if(node.rchild!=-1)
                {
                        T.nodes[node.rchild].huffmanCode=node.huffmanCode+"1";
                        q.push(T.nodes[node.rchild]);
                }
        }

}
