{
        HuffmanTree T;
        int n;
        int w[110];
        cin>>n;
        for(int i=0;i<n;i++)
          cin>>w[i];
        CreateHuffmanTree(T,n,w);
        CalcHuffmanCode(T);
        for(int i=0;i<T.leafnumber;i++)
        {
                cout<<T.nodes[i].huffmanCode<<endl;
        }

}

