    int m=2*n-1;
    for(int i=1;i<=n;i++)
    {
        node[i].parent=node[i].lchild=node[i].rchild=0;
        node[i].weight=w[i];
    }
    for(int i=n+1;i<=m;i++)
    {
        int a,b;
        searchmin(a,b,i-1);
        node[i].lchild=a;
        node[i].rchild=b;
        node[i].weight=node[a].weight+node[b].weight;
        node[i].parent=0;
        node[a].parent=node[b].parent=i;
    }
    int c,f,index=0;
    char temp[n];
    ans=new char *[n+1];
    for(int i=1;i<=m;i++)
        node[i].weight=0;
    while(m)
    {
        if(node[m].weight==0)
        {
            node[m].weight=1;
            if(node[m].lchild!=0)
            {
                m=node[m].lchild;
                temp[index++]='0';
            }
            else if(node[m].rchild==0)
            {
                ans[m]=new char[index+1];
                temp[index]='\0';
                strcpy(ans[m],temp);
            }
        }
        else if(node[m].weight==1)
        {
            node[m].weight=2;
            if(node[m].rchild!=0)
            {
                m=node[m].rchild;
                temp[index++]='1';
            }
        }
        else
        {
            node[m].weight=0;
            m=node[m].parent;
            --index;
        }
    }
}
