// 直接插入排序函数
void InsertSort(SqList *L) {
    int i, j;
    for (i = 2; i <= L->length; ++i) { // 从第2个元素开始插入
        if (L->r[i] < L->r[i-1]) {     // 当前元素小于前一个元素时，需要插入
            L->r[0] = L->r[i];         // 哨兵，存储当前待插入元素
            for (j = i - 1; L->r[0] < L->r[j]; --j) {
                L->r[j + 1] = L->r[j]; // 记录后移
            }
            L->r[j + 1] = L->r[0];     // 插入到正确位置
        }
    }
}

