#include <iostream>
using namespace std;
 
const int MAXSIZE = 100000;
 
typedef struct {
    int key;
} RedType;
 
typedef struct {
    RedType r[MAXSIZE + 1];
    int length;
} Sqlist;
 
int Partition(Sqlist &L, int low, int high) {
    L.r[0] = L.r[low]; // 用第一个记录作枢轴记录
    int pivotkey = L.r[low].key; // 枢轴记录关键字
     
    while (low < high) {
        // 从高端向低端扫描，找到第一个小于枢轴的记录
        while (low < high && L.r[high].key >= pivotkey) --high;
        L.r[low] = L.r[high]; // 将比枢轴小的记录移到低端
         
        // 从低端向高端扫描，找到第一个大于枢轴的记录
        while (low < high && L.r[low].key <= pivotkey) ++low;
        L.r[high] = L.r[low]; // 将比枢轴大的记录移到高端
    }
     
    L.r[low] = L.r[0]; // 枢轴记录到位
    return low; // 返回枢轴位置
}
 
void QSort(Sqlist &L, int low, int high) {
    if (low < high) { // 长度大于1
        int pivotloc = Partition(L, low, high); // 将序列一分为二
        QSort(L, low, pivotloc - 1); // 对低子表递归排序
        QSort(L, pivotloc + 1, high); // 对高子表递归排序
    }
}
 
void QuickSort(Sqlist &L) {
    QSort(L, 1, L.length);
}
 
int main() {
    int n;
    cin >> n;
     
    Sqlist L;
    L.length = n;
     
    // 读取数据，从位置1开始存储
    for (int i = 1; i <= n; i++) {
        cin >> L.r[i].key;
    }
     
    QuickSort(L);
     
    // 输出排序结果
    for (int i = 1; i <= n; i++) {
        cout << L.r[i].key << " ";
    }
    cout << endl;
     
    return 0;
}

