// 分区函数：返回基准元素的最终位置，左部分≤基准，右部分≥基准
int partition(vector<int>& arr, int low, int high) {
    // 随机选择基准元素（避免有序序列的最坏情况）
    int pivotIdx = low + rand() % (high - low + 1);
    swap(arr[low], arr[pivotIdx]);  // 将基准交换到左端点，简化逻辑
    int pivot = arr[low];           // 基准值

    int left = low;
    int right = high;

    while (left < right) {
        // 右指针：从右往左找第一个小于基准的元素
        while (left < right && arr[right] >= pivot) {
            right--;
        }
        // 左指针：从左往右找第一个大于基准的元素
        while (left < right && arr[left] <= pivot) {
            left++;
        }
        // 交换左右指针指向的元素（若指针未交叉）
        if (left < right) {
            swap(arr[left], arr[right]);
        }
    }
    // 将基准元素放到最终正确位置（left与right重合处）
    swap(arr[low], arr[left]);
    return left;  // 返回基准位置，用于分割子序列
}

// 快速排序递归函数
void quickSort(vector<int>& arr, int low, int high) {
    if (low < high) {  // 子序列长度≥2时才需排序
        int pivotPos = partition(arr, low, high);  // 分区得到基准位置
        quickSort(arr, low, pivotPos - 1);         // 递归排序左子序列
        quickSort(arr, pivotPos + 1, high);        // 递归排序右子序列
    }
}

