void heap_adjust(vector<int> &a, int s, int m) {
    int rc = a[s];
    for (int j = 2 * s; j <= m; j *= 2) {
        if (j < m && a[j] < a[j + 1]) {
            ++j;
        }
        if (rc >= a[j]) {
            break;
        }
        a[s] = a[j];
        s = j;
    }
    a[s] = rc;
}

void heap_sort(vector<int> &a, int n) {
    for (int i = n / 2; i >= 1; --i) {
        heap_adjust(a, i, n);
    }
    for (int i = n; i > 1; --i) {
        int tmp = a[1];
        a[1] = a[i];
        a[i] = tmp;
        heap_adjust(a, 1, i - 1);
    }
}

