struct HeapType {
    vector<int> r;
    int length;
};

void HeapAdjust(HeapType &H, int s, int m) {
    int rc = H.r[s];
    for (int j = 2 * s; j <= m; j *= 2) {
        if (j < m && H.r[j] < H.r[j + 1]) ++j;
        if (rc >= H.r[j]) break;
        H.r[s] = H.r[j];
        s = j;
    }
    H.r[s] = rc;
}

void HeapSort(HeapType &H) {
    for (int i = H.length / 2; i > 0; --i)
        HeapAdjust(H, i, H.length);
    for (int i = H.length; i > 1; --i) {
        swap(H.r[1], H.r[i]);
        HeapAdjust(H, 1, i - 1);
    }
}

