#define MAXN 100000

void siftDown(int arr[], int start, int end) {
    int root = start;
    while (2 * root + 1 <= end) {
        int child = 2 * root + 1;
        if (child + 1 <= end && arr[child] < arr[child + 1]) {
            child++; 
        }
        if (arr[root] >= arr[child]) {
            break;
        }

        int tmp = arr[root];
        arr[root] = arr[child];
        arr[child] = tmp;
        root = child;
    }
}

void heapSort(int arr[], int n) {
   
    for (int i = (n - 2) / 2; i >= 0; i--) {
        siftDown(arr, i, n - 1);
    }

   
    for (int i = n - 1; i > 0; i--) {

        int tmp = arr[0];
        arr[0] = arr[i];
        arr[i] = tmp;

        siftDown(arr, 0, i - 1);
    }
}

