template <typename T>
void heapify(T *a, int n, int i)
{
    int l = 2 * i + 1, r = 2 * i + 2, mx = i;
    if (l < n && a[l] > a[mx])
        mx = l;
    if (r < n && a[r] > a[mx])
        mx = r;
    if (mx != i)
    {
        std::swap(a[i], a[mx]);
        heapify(a, n, mx);
    }
}
template <typename T>
void heapSort(T *a, int n)
{
    for (int i = n / 2 - 1; i >= 0; --i)
        heapify(a, n, i);
    for (int i = n - 1; i > 0; --i)
    {
        std::swap(a[0], a[i]);
        heapify(a, i, 0);
    }
}
