#include <stdio.h>

#define MAX_N 100000

// 定义堆元素结构体
typedef struct {
    int key;
} RedType;

// 定义堆的结构体
typedef struct {
    RedType r[MAX_N + 1];  // r[0]不使用，r[1]到r[n]存储堆的元素
    int length;  // 堆的大小
} HeapType;

// 交换堆中的两个元素
void swap(RedType *a, RedType *b) {
    RedType temp = *a;
    *a = *b;
    *b = temp;
}

// 调整堆，使得 H.r[s..m] 变成一个大顶堆
void HeapAdjust(HeapType *H, int s, int m) {
    int j;
    RedType rc = H->r[s];  // 保存当前节点
    for (j = 2 * s; j <= m; j *= 2) {  // 沿key较大的孩子结点向下筛选
        if (j < m && H->r[j].key < H->r[j + 1].key) {  // 如果右子节点更大
            ++j;
        }
        if (rc.key >= H->r[j].key) {  // 如果当前节点的key已经大于或等于子节点
            break;
        }
        // 否则，把较大的子节点上移
        H->r[s] = H->r[j];
        s = j;
    }
    H->r[s] = rc;  // 插入到合适的位置
}

// 堆排序函数
void HeapSort(HeapType *H) {
    int i;
    RedType temp;
    // Step 1: 构建大根堆
    for (i = H->length / 2; i > 0; --i) {  // 从最后一个非叶子节点开始调整堆
        HeapAdjust(H, i, H->length);
    }
    
    // Step 2: 进行排序
    for (i = H->length; i > 1; --i) {
        // 将堆顶元素与当前最后一个元素交换
        swap(&H->r[i], &H->r[1]);
        
        // 调整堆，使堆重新符合大顶堆的性质
        HeapAdjust(H, 1, i - 1);
    }
}

// 主函数
int main() {
    int n;
    scanf("%d", &n);
    
    HeapType H;
    H.length = n;
    
    // 输入n个整数
    for (int i = 1; i <= n; i++) {
        scanf("%d", &H.r[i].key);
    }
    
    // 执行堆排序
    HeapSort(&H);
    
    // 输出排序后的结果
    for (int i = 1; i <= n; i++) {
        printf("%d ", H.r[i].key);
    }
    printf("\n");
    
    return 0;
}

