}
bool isBigDipperNumber(long long num) {
	if (num < 1000000 || num > 9999999) {
		return false;
	}
	long long original = num;
	long long sum = 0;
	while (num > 0) {
		int digit = num % 10;
		sum += pow7(digit);
		num /= 10;
	}
	return sum == original;
}
