using namespace std;

bool allDigitsInSet(int number, const unordered_set<char>& digitSet) {
    string s = to_string(number);
    for (char c : s) {
        if (digitSet.find(c) == digitSet.end()) {
            return false;
        }
    }
    return true;
}

int solve(const string& digitSetStr) {
    unordered_set<char> digitSet;
    for (char c : digitSetStr) {
        digitSet.insert(c);
    }

    int count = 0;
    for (int abc = 100; abc <= 999; ++abc) {
        if (!allDigitsInSet(abc, digitSet)) {
            continue;
        }
        for (int de = 10; de <= 99; ++de) {
            if (!allDigitsInSet(de, digitSet)) {
                continue;
            }
            int e = de % 10;
            int d = de / 10;
            int p1 = abc * e;
            if (!allDigitsInSet(p1, digitSet)) {
                continue;
            }
            int p2 = abc * d;
            if (!allDigitsInSet(p2, digitSet)) {
                continue;
            }
            int p = abc * de;
            if (!allDigitsInSet(p, digitSet)) {
                continue;
            }
            ++count;
        }
    }
    return count;
}

int main() {
    string line;
    while (getline(cin, line)) {
        if (line.empty()) {
            continue;
        }
        cout << solve(line) << endl;
    }
    return 0;
}

