using namespace std;

// 十六进制字符转4位二进制字符串
string hexToBin(char c) {
    switch (c) {
        case '0': return "0000";
        case '1': return "0001";
        case '2': return "0010";
        case '3': return "0011";
        case '4': return "0100";
        case '5': return "0101";
        case '6': return "0110";
        case '7': return "0111";
        case '8': return "1000";
        case '9': return "1001";
        case 'A': return "1010";
        case 'B': return "1011";
        case 'C': return "1100";
        case 'D': return "1101";
        case 'E': return "1110";
        case 'F': return "1111";
        default: return "";
    }
}

// 3位二进制字符串转八进制字符
char binToOct(string s) {
    int val = stoi(s, nullptr, 2);
    return '0' + val;
}

int main() {
    string hexStr;
    cin >> hexStr;
    
    // 特殊情况：输入为0
    if (hexStr == "0") {
        cout << "0" << endl;
        return 0;
    }
    
    // 十六进制转二进制
    string binStr;
    for (char c : hexStr) {
        binStr += hexToBin(c);
    }
    
    // 补前导0，让二进制长度是3的倍数
    int pad = (3 - binStr.size() % 3) % 3;
    binStr = string(pad, '0') + binStr;
    
    // 二进制转八进制
    string octStr;
    for (int i = 0; i < binStr.size(); i += 3) {
        string sub = binStr.substr(i, 3);
        octStr += binToOct(sub);
    }
    
    // 去掉前导0
    size_t start = octStr.find_first_not_of('0');
    octStr = octStr.substr(start);
    
    cout << octStr << endl;
    
    return 0;
}

