int countSubstringsContaining(const std::string& str, const std::string& pattern) {
    int n = str.length();
    int m = pattern.length();
    int count = 0;


    for (int i = 0; i <= n - m; ++i) {

        bool found = true;
        for (int j = 0; j < m; ++j) {
            if (str[i + j] != pattern[j]) {
                found = false;
                break;
            }
        }
  
        if (found) {
            ++count;
        }
    }


    count = 0;
    for (int len = m; len <= n; ++len) { 
        for (int start = 0; start <= n - len; ++start) { 
            std::string substr = str.substr(start, len);
            if (substr.find(pattern) != std::string::npos) {
                ++count;
            }
        }
    }

    return count;
}

