#include <iostream>
#include <vector>
#include <unordered_set>
#include <algorithm>
using namespace std;

int main() {
    // 预处理dp数组：dp[i]存储i条直线的所有可能的平行组平方和
    vector<unordered_set<int>> dp(21);
    dp[0].insert(0); // 0条直线的平方和为0
    for (int i = 1; i <= 20; ++i) {
        for (int j = 1; j <= i; ++j) { // 最后一个平行组的大小为j
            for (int s : dp[i - j]) {
                dp[i].insert(s + j * j); // 累加j²
            }
        }
    }

    int n;
    // 处理多个测试用例
    while (cin >> n) {
        vector<int> res;
        // 计算所有可能的交点数
        for (int s : dp[n]) {
            int cnt = (n * n - s) / 2;
            res.push_back(cnt);
        }
        // 排序后输出
        sort(res.begin(), res.end());
        for (size_t i = 0; i < res.size(); ++i) {
            if (i > 0) cout << " ";
            cout << res[i];
        }
        cout << endl;
    }

    return 0;
}

