			else if(s[i]>='j'&&s[i]<='l')cout<<'5';
			else if(s[i]>='m'&&s[i]<='o')cout<<'6';
			else if(s[i]>='p'&&s[i]<='s')cout<<'7';
			else if(s[i]>='t'&&s[i]<='v')cout<<'8';
			else if(s[i]>='w'&&s[i]<='z')cout<<'9';
		}
		else cout<<s[i];
	}
	cout<<endl;
}
