#include <iostream>
#include <string>
using namespace std;

int main() {
    string s;
    while (cin >> s) { // 支持多组测试数据
        string res;
        for (char c : s) {
            if (c >= 'A' && c <= 'Z') {
                // 大写字母：先转小写，再后移一位（Z 后移为 a）
                char lower_c = tolower(c);
                if (lower_c == 'z') {
                    res += 'a';
                } else {
                    res += (char)(lower_c + 1);
                }
            } else if (c >= 'a' && c <= 'z') {
                // 小写字母：映射到数字
                if (c >= 'a' && c <= 'c') res += '2';
                else if (c >= 'd' && c <= 'f') res += '3';
                else if (c >= 'g' && c <= 'i') res += '4';
                else if (c >= 'j' && c <= 'l') res += '5';
                else if (c >= 'm' && c <= 'o') res += '6';
                else if (c >= 'p' && c <= 's') res += '7';
                else if (c >= 't' && c <= 'v') res += '8';
                else if (c >= 'w' && c <= 'z') res += '9';
            } else {
                // 数字和其他符号不做变换
                res += c;
            }
        }
        cout << res << endl;
    }
    return 0;
}

