using namespace std;

typedef struct Stack{
	char val[101] = {'0'};
	int p = 0;
	
	void pop(){
		p--;
	}
	
	char peek(){
		return val[p-1];
	}
	
	int getSize(){
		return p;
	}
	
	void push(char c){
		val[p] = c;
		p++;
	}
	
	void print(){
		int i = p;
		while(p--)cout << val[p] << " " << endl;
	}
}Stack;

int main(){
	string st;
	while(cin >> st){
		int res = 0;
		Stack stack;
		for(int i = 0;i < st.size();i++){
			if(stack.getSize() == 0){
				stack.push(st[i]);
				continue;
			}
			if(st[i] == '('){
				
				stack.push('(');
				
			}else{
				
				if(stack.peek()=='('){
				
					res++;
					stack.pop();
				}
			}
		}
		cout << res << endl;
	}
	return 0;
}

